    img3: 'https://images.ctfassets.net/1aemqu6a6t65/4hQFNm7rQvHHKaPjsx2FZ0/174e4cf2006c9876fec57b46b0ea98b1/PS1-Long_Island_CIty-Queens-NYC-Photo-.jpg',
